function uuidv4() {
  if (globalThis.crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function statusFrom(raw, msg) {
  const s = String(raw == null ? '' : raw).toLowerCase();
  const m = String(msg || '').toLowerCase();
  if (s === '1' || s === 'up' || s === 'resolved' || m.includes('up') || m.includes('recover')) return 'resolved';
  if (s === '0' || s === 'down' || s === 'open' || m.includes('down') || m.includes('fail')) return 'open';
  return 'open';
}

const root = $input.first().json || {};
let body = root.body || root;
// Replay payloads may carry the full webhook envelope ({headers,query,body}); unwrap it.
if (body && typeof body === 'object' && body.body && typeof body.body === 'object' && (body.headers || body.query || body.webhookUrl)) body = body.body;
const monitor = body.monitor || body.heartbeat || body.data || {};
const replay = !!root.replay;
const response_required = !!root.body && !replay;
const monitor_id = String(body.monitor_id || monitor.id || monitor.monitorID || body.id || 'unknown');
const monitor_name = body.monitor_name || monitor.name || monitor.hostname || body.name || 'Unknown monitor';
const status = body.incident_status || body.status || monitor.status;
const incident_status = statusFrom(status, body.msg || body.message || monitor.msg);
const sevRaw = String(body.severity || '').toLowerCase();
const severity = ['minor', 'major', 'critical'].includes(sevRaw) ? sevRaw : (incident_status === 'open' ? 'major' : 'minor');
const region = body.region || monitor.region || (Array.isArray(body.tags) ? (body.tags.find(t => /^region:/i.test(String(t))) || '').split(':')[1] : null) || null;
const tenant_id = body.tenant_id || root.tenant_id || null;
const event_id = body.event_id || body.heartbeat_id || monitor.heartbeatID || body.id || (monitor_id + ':' + incident_status + ':' + (body.time || body.created_at || 'latest'));
const idem_key = 'incident:' + event_id;
const correlation_id = replay && root.correlation_id ? root.correlation_id : uuidv4();

return [{ json: {
  tenant_id,
  monitor_id,
  monitor_name,
  incident_status,
  severity,
  region,
  message: body.msg || body.message || monitor.msg || null,
  event_id,
  idem_key,
  replay,
  response_required,
  correlation_id,
  execution_id: String($execution.id),
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, '')
} }];

const p = $('Normalize Incident').first().json;
// Fetch Impacted Tenants runs with fullResponse:true -> single wrapper item {body,statusCode,...}
// even when PostgREST returns []. body is the tenant array; anything else (HTTP error with
// onError:continueRegularOutput) degrades to zero impacted tenants.
const resp = $('Fetch Impacted Tenants').first().json || {};
const tenants = Array.isArray(resp.body) ? resp.body.filter(t => t && t.id) : [];
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, monitor_id: p.monitor_id, monitor_name: p.monitor_name, severity: p.severity, status: p.incident_status === 'resolved' ? 'resolved' : 'open', region: p.region, impact_count: tenants.length, impacted_tenants: tenants.map(t => ({ id: t.id, name: t.name, plan: t.plan, region: t.region })), postmortem: { message: p.message, source: p.replay ? 'replay' : 'uptime-kuma', event_id: p.event_id } } }];

