const p = $('Normalize Incident').first().json;
const row = $('Prep Incident Row').first().json;
const text = [
  p.incident_status === 'resolved' ? 'Incident resolved' : 'Incident opened',
  'Monitor: ' + p.monitor_name + ' (' + p.monitor_id + ')',
  'Severity: ' + p.severity + (p.region ? ' | Region: ' + p.region : ''),
  'Impacted active tenants: ' + row.impact_count,
  'Correlation: `' + p.correlation_id + '`'
].join('\n');
let alert_delivered = false;
let notice = null;
const token = $env.TELEGRAM_BOT_TOKEN;
const chat = $env.TELEGRAM_CHAT_ID;
if (token && chat) {
  try {
    await this.helpers.httpRequest({ method: 'POST', url: 'https://api.telegram.org/bot' + token + '/sendMessage', body: { chat_id: chat, text, parse_mode: 'Markdown' }, json: true });
    alert_delivered = true;
  } catch (e) {
    notice = 'telegram failed: ' + (e && e.message ? e.message : String(e));
  }
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, alert_delivered, notice, impact_count: row.impact_count } }];

const p = $('Normalize Incident').first().json;
const n = $('Notify Telegram').first().json;
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, service: 'incident', step: 'segment-tenants', status: 'success', payload: { monitor_id: p.monitor_id, status: p.incident_status, region: p.region, impact_count: n.impact_count, telegram_delivered: n.alert_delivered, notice: n.notice } } }];
